    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int[] pi = new int[N];
            int[] li = new int[N];
            for (int i = 0; i < N; i++) {
                pi[i] = scanner.nextInt();
                li[i] = scanner.nextInt();
            }
            int min_satellites = N;
            for (int t = 0; t < 360; t++) {
                int visible_satellites = 0;
                for (int i = 0; i < N; i++) {
                    double x = Math.sin(Math.toRadians(pi[i] + t)) * Math.cos(Math.toRadians(li[i]));
                    double y = Math.sin(Math.toRadians(pi[i] + t)) * Math.sin(Math.toRadians(li[i]));
                    double z = Math.cos(Math.toRadians(pi[i] + t));
                    if (x > 0 || (x == 0 && y > 0)) {
                        visible_satellites++;
                    }
                }
                min_satellites = Math.min(min_satellites, visible_satellites);
            }
            System.out.println(min_satellites);
        }
    }
